/**
 * @param {import('knex').Knex} knex
 */
exports.seed = async function (knex) {
  const crypto = require('crypto');

  const existing = await knex('provinces').count('* as count').first();
  if (parseInt(existing.count, 10) > 0) {
    console.log('Provinces already seeded, skipping.');
    return;
  }

  // Generate UUIDs for each province (SQLite has no built-in uuid()).
  // subregion must be explicit on every row (not just Tier 0 ones) — the
  // libsql dialect's batch insert can't fill in missing keys across a
  // mixed-shape array the way some SQL dialects do.
  const provincesWithIds = provinces.map(p => ({ id: crypto.randomUUID(), subregion: null, ...p }));

  // Insert in a single transaction to avoid per-batch autocommit overhead
  const batchSize = 50;
  await knex.transaction(async (trx) => {
    for (let i = 0; i < provincesWithIds.length; i += batchSize) {
      await trx('provinces').insert(provincesWithIds.slice(i, i + batchSize));
    }
  });

  console.log(`Seeded ${provinces.length} provinces across 36 countries.`);
};
